solution_code:
#include <iostream>

template <typename T>
class Val
{
    T m_val{};
public:
    Val(T v) : m_val{v} {}

    Val<T> operator+(const Val<T>& rhs) const
    {
        return Val<T>{m_val + rhs.m_val};
    }

    friend std::ostream& operator<<(std::ostream& out, const Val<T>& v)
    {
        out << v.m_val;
        return out;
    }
};

template <typename T>
T accumulate3(T a, T b, T c)
{
    return a + b + c;
}

int main()
{
    int a{};
    int b{};
    int c{};
    std::cin >> a >> b >> c;

    std::cout << accumulate3(Val<int>{a}, Val<int>{b}, Val<int>{c}) << '\n';

    return 0;
}
